# Search for entries where normalized text contains 'ادخل' and 'قبل' within 10 tokens
def token_overlap_near(txt, a, b, max_dist=6):
    norm = normalize_ar(txt)
    toks = norm.split()
    positions_a = [i for i,t in enumerate(toks) if t==a]
    positions_b = [i for i,t in enumerate(toks) if t==b]
    for i in positions_a:
        for j in positions_b:
            if abs(i-j) <= max_dist:
                return True, norm, toks, i, j
    return False, norm, toks, positions_a, positions_b

